+        assert_eq!(rejection.session_id, "s2");
+        assert_eq!(rejection.trace_id, "trace-second");
+        assert_eq!(rejection.timestamp, 2_000);
+        assert_eq!(
+            rejection.detail,
+            "max sessions reached: active_sessions=1 limit=1"
+        );
+    }
